def format_output(data, json_output: bool = False) -> str:
    """Format output data as JSON or readable text."""
    if json_output:
        return json.dumps(data, indent=2, default=str)
    if isinstance(data, dict):
        lines = []
        for key, value in data.items():
            if isinstance(value, dict):
                lines.append(f"  {key}:")
                for k, v in value.items():
                    lines.append(f"    {k}: {v}")
            elif isinstance(value, (list, set)):
                lines.append(f"  {key}: {', '.join(str(v) for v in sorted(value))}")
            else:
                lines.append(f"  {key}: {value}")
        return "\n".join(lines)
    elif isinstance(data, list):
        return "\n".join(f"  - {item}" for item in data)
    return str(data)


def main():
    """Main entry point for the Kafka admin script."""
    parser = build_parser()
    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    if args.verbose:
        logging.getLogger().setLevel(logging.DEBUG)

    # Initialize admin client
    try:
        admin = KafkaClusterAdmin(
            bootstrap_servers=args.bootstrap_servers,
            client_id=args.client_id,
            security_protocol=args.security_protocol,
            sasl_mechanism=args.sasl_mechanism,
            sasl_plain_username=args.sasl_username,
            sasl_plain_password=args.sasl_password,
            ssl_cafile=args.ssl_cafile,
            ssl_certfile=args.ssl_certfile,
            ssl_keyfile=args.ssl_keyfile,
        )
    except Exception as e:
        logger.error("Failed to initialize Kafka admin client: %s", e)
        sys.exit(1)

    exit_code = 0

    try:
        if args.command == "create":
            configs = parse_config_args(args.config)
            success = admin.create_topic(
                topic_name=args.topic,
                num_partitions=args.partitions,
                replication_factor=args.replication_factor,
                topic_configs=configs,
            )
            if success:
                result = {
                    "status": "created",
                    "topic": args.topic,
                    "partitions": args.partitions,
                    "replication_factor": args.replication_factor,
                    "configs": configs,
                }
                print(format_output(result, args.json_output))
            else:
                result = {"status": "already_exists", "topic": args.topic}
                print(format_output(result, args.json_output))
                exit_code = 1

        elif args.command == "create-batch":
            topics = parse_topics_file(args.topics_file)
            results = admin.create_topics_batch(topics)
            print(format_output(results, args.json_output))

        elif args.command == "delete":
            success = admin.delete_topic(args.topic)
            if success:
                result = {"status": "deleted", "topic": args.topic}
                print(format_output(result, args.json_output))
            else:
                result = {"status": "not_found", "topic": args.topic}
                print(format_output(result, args.json_output))
                exit_code = 1

        elif args.command == "delete-batch":
            success = admin.delete_topics_batch(args.topics)
            result = {
                "status": "deleted" if success else "failed",
                "topics": args.topics,
            }
            print(format_output(result, args.json_output))

        elif args.command == "list":
            topics = admin.list_topics()
            if args.json_output:
                print(json.dumps({"topics": topics, "count": len(topics)}, indent=2))
            else:
                print(f"Topics ({len(topics)}):")
                print(format_output(topics))

        elif args.command == "describe":
            topic_info = admin.describe_topic(args.topic)
            if topic_info:
                if args.json_output:
                    print(json.dumps(topic_info, indent=2, default=str))
                else:
                    print(f"Topic: {args.topic}")
                    print(format_output(topic_info))
            else:
                print(f"Topic '{args.topic}' not found.")
                exit_code = 1

        elif args.command == "add-partitions":
            success = admin.add_partitions(args.topic, args.partitions)
            result = {
                "status": "updated" if success else "failed",
                "topic": args.topic,
                "total_partitions": args.partitions,
            }
            print(format_output(result, args.json_output))
            if not success:
                exit_code = 1

        elif args.command == "alter-config":
            configs = parse_config_args(args.config)
            success = admin.alter_topic_config(args.topic, configs)
            result = {
                "status": "updated" if success else "failed",
                "topic": args.topic,
                "configs": configs,
            }
            print(format_output(result, args.json_output))

        elif args.command == "describe-config":
            config = admin.describe_topic_config(args.topic)
            if config:
                if args.json_output:
                    print(json.dumps({"topic": args.topic, "configs": config}, indent=2))
                else:
                    print(f"Configuration for topic '{args.topic}':")
                    for key in sorted(config.keys()):
                        print(f"  {key} = {config[key]}")
            else:
                print(f"No configuration found for topic '{args.topic}'.")
                exit_code = 1

        elif args.command == "describe-cluster":
            cluster_info = admin.describe_cluster()
            if args.json_output:
                print(json.dumps(cluster_info, indent=2, default=str))
            else:
                print("Cluster Information:")
                print(format_output(cluster_info))

    except KafkaError as e:
        logger.error("Kafka error: %s", e)
        if args.json_output:
            print(json.dumps({"error": str(e)}, indent=2))
        exit_code = 1
    except Exception as e:
        logger.error("Unexpected error: %s", e)
        if args.json_output:
            print(json.dumps({"error": str(e)}, indent=2))
        exit_code = 1
    finally:
        admin.close()

    sys.exit(exit_code)


if __name__ == "__main__":
    main()